class TreeNode {
  constructor(val) {
    this.val = val;
    this.left = null;
    this.right = null;
  }
}

class Solution {
  buildTree(inorder, postorder) {
    if (inorder.length !== postorder.length) return null;

    const hm = new Map();
    inorder.forEach((val, idx) => hm.set(val, idx));

    return this._build(inorder, 0, inorder.length - 1,
                       postorder, 0, postorder.length - 1, hm);
  }

  _build(inorder, is, ie, postorder, ps, pe, hm) {
    if (ps > pe || is > ie) return null;

    const rootVal = postorder[pe];
    const root = new TreeNode(rootVal);
    const inRoot = hm.get(rootVal);
    const numsLeft = inRoot - is;

    root.left = this._build(inorder, is, inRoot - 1,
                            postorder, ps, ps + numsLeft - 1, hm);
    root.right = this._build(inorder, inRoot + 1, ie,
                             postorder, ps + numsLeft, pe - 1, hm);
    return root;
  }
}

function printInorder(root) {
  if (!root) return;
  printInorder(root.left);
  process.stdout.write(root.val + " ");
  printInorder(root.right);
}

